import { graphql } from 'gatsby';
import React from 'react';
import { Helmet } from 'react-helmet';
import { BlogType } from '../../components/organisms/Blogs';
import { Section } from '../../components/organisms/Navbar';
import AboutTemplate from '../../components/templates/About';
import {
  about,
  cta,
  hero,
  newsletter,
  portfolio,
  stats,
  team,
  testimonials,
} from '../../data';

const sections: Section[] = [
  { id: 'about' },
  { id: 'stats' },
  { id: 'portfolio' },
  { id: 'techstack' },
  { id: 'testimonials' },
  { id: 'blogs' },
];

export type AboutPageProps = {
  data: {
    allMdx: {
      nodes: [
        {
          id: string;
          slug: string;
          frontmatter: { title: string; description: string; date: string };
        }
      ];
    };
  };
};

const AboutPage: React.FC<AboutPageProps> = ({ data }) => {
  const blogs: BlogType[] = data.allMdx.nodes.map((node) => {
    const {
      id,
      frontmatter = { title: '', description: '', date: '' },
      slug,
    } = node;
    const { title, description, date } = frontmatter;
    return { id, url: '/blogs/' + slug, title, description, date };
  });

  return (
    <>
      <Helmet>
        <meta charSet="utf-8" />
        <title>HIEU DOAN (hieudoanm): About</title>
      </Helmet>
      <AboutTemplate
        sections={sections}
        hero={hero}
        about={about}
        stats={stats}
        logos={portfolio}
        team={team}
        cta={cta}
        testimonials={testimonials}
        blogs={{
          id: 'blogs',
          title: 'Blogs',
          subtitle:
            'Keep updated with new technologies and stories from other developers.',
          blogs,
        }}
        newsletter={newsletter}
      />
    </>
  );
};

export const query = graphql`
  query {
    allMdx(sort: { fields: frontmatter___title, order: ASC }, limit: 4) {
      nodes {
        frontmatter {
          title
          date(formatString: "MMMM D, YYYY")
          author
          description
        }
        id
        body
        slug
      }
    }
  }
`;

export default AboutPage;
